// Pega a resposta da API
let content = $json.choices[0].message.content || "";

// Remove blocos de código markdown (```tsx, ```typescript, ```)
content = content.replace(/^```(?:tsx|typescript|ts|jsx|javascript|js)?\s*\n?/gm, "");
content = content.replace(/```\s*$/gm, "");

// Remove possíveis explicações antes do código (tudo antes do primeiro import ou 'use client')
const codeStart = content.search(/^(import |['"]use client['"]|export )/m);
if (codeStart > 0) {
  content = content.substring(codeStart);
}

// Remove possíveis explicações depois do código (tudo após o último })
const lastBrace = content.lastIndexOf("}");
if (lastBrace !== -1) {
  content = content.substring(0, lastBrace + 1);
}

// Remove linhas em branco extras no início e fim
content = content.trim();

return [
  {
    codigo_tsx: content,
  }
];

