const url = $input.first().json.body.url

const partes = url.split('/').filter(p => p !== '');

const slug_da_modalidade = partes[partes.length - 2];
const slug_do_curso = partes[partes.length - 1];

return {
  slug_da_modalidade,
  slug_do_curso
};

// Aceita tanto string JSON quanto objeto já parseado
const inputData = $input.first().json.body?.data ?? $input.first().json;
const raw = typeof inputData === 'string' ? JSON.parse(inputData) : inputData;

// ─── Dados principais ───────────────────────────────────────
const nome_curso    = raw?.nome_curso ?? null;
const slug_curso    = raw?.slug_curso ?? null;
const grupo_curso   = raw?.grupo_curso ?? null;
const carga_horaria = raw?.carga_horaria ?? null;
const data_inicio   = raw?.data_inicio ?? null;
const duracao_curso = raw?.duracao_curso ?? null;
const qtd_vagas     = raw?.quantidade_vagas ?? null; // no JSON atual pode não existir
const instagram_url = raw?.instagram_url ?? null;
const ebook_url     = raw?.ebook_url ?? null;
const briefing      = raw?.briefing_nome ?? null;

// ─── Cores ──────────────────────────────────────────────────
const cor_primaria   = raw?.cores?.[0] ?? null;
const cor_secundaria = raw?.cores?.[1] ?? null;
const cor_terciaria  = raw?.cores?.[2] ?? null;

// ─── Tipo / Modalidade ──────────────────────────────────────
// No JSON real veio como objeto: tipo_curso
const tipo = raw?.tipo_curso ?? {};

const tipo_codigo          = tipo?.codigo ?? null;
const tipo_codigo_curso    = tipo?.codigo_curso ?? null;
const tipo_descricao       = tipo?.descricao ?? null;
const tipo_slug_modalidade = tipo?.slug_modalidade ?? null;

// ─── Imagem principal ───────────────────────────────────────
const imagem = raw?.imagens?.[0] ?? {};

const imagem_url    = imagem?.imagem ?? null;
const imagem_secao  = imagem?.secao ?? null;
const imagem_slider = imagem?.slider ?? null;

// ─── Coordenador ────────────────────────────────────────────
const coord = raw?.coordenadores?.[0] ?? {};

const coord_nome      = coord?.nome ?? null;
const coord_email     = coord?.email ?? null;
const coord_descricao = coord?.descricao ?? null;
const coord_imagem    = coord?.imagem ?? null;

// ─── Retorno flat ───────────────────────────────────────────
return [
  {
    json: {
      nome_curso,
      slug_curso,
      grupo_curso,
      carga_horaria,
      data_inicio,
      duracao_curso,
      qtd_vagas,
      instagram_url,
      ebook_url,
      briefing,

      cor_primaria,
      cor_secundaria,
      cor_terciaria,

      tipo_codigo,
      tipo_codigo_curso,
      tipo_descricao,
      tipo_slug_modalidade,

      imagem_url,
      imagem_secao,
      imagem_slider,

      coord_nome,
      coord_email,
      coord_descricao,
      coord_imagem,
    }
  }
];
